sql:
SELECT puzzle_id
FROM puzzle_performance
WHERE success_rate = (SELECT MAX(success_rate) FROM puzzle_performance);

SELECT puzzle_name, difficulty_level
FROM puzzles
ORDER BY difficulty_level;

SELECT team_id, average_score, total_puzzles_solved
FROM team_performance
ORDER BY average_score DESC;

SELECT name, experience_level
FROM game_masters
WHERE training_status = 'trained' AND experience_level = 'expert';

SELECT average_solve_time
FROM puzzle_performance
WHERE puzzle_id = 1;

SELECT team_id, rank
FROM rankings
ORDER BY rank ASC;

SELECT puzzle_id, average_solve_time AS avg_solve_time
FROM puzzle_performance
ORDER BY avg_solve_time DESC;

SELECT name
FROM game_masters
WHERE experience_level = (
    SELECT MAX(experience_level) 
    FROM game_masters
);

